import React, { useState, useEffect } from "react";
import { api } from "../api";

export default function StudentDashboard() {
  const [complaints, setComplaints] = useState([]);
  const [form, setForm] = useState({ category: "", description: "", priority: "Low" });

  const fetchComplaints = async () => {
    const res = await api.get("/complaints/mine");
    setComplaints(res.data);
  };

  useEffect(() => {
    fetchComplaints();
  }, []);

  const handleSubmit = async (e) => {
    e.preventDefault();
    await api.post("/complaints", form);
    setForm({ category: "", description: "", priority: "Low" });
    fetchComplaints();
  };

  return (
    <div className="container mt-5">
      <h2>Submit Complaint</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Category"
          className="form-control mb-2"
          value={form.category}
          onChange={(e) => setForm({ ...form, category: e.target.value })}
          required
        />
        <textarea
          placeholder="Description"
          className="form-control mb-2"
          value={form.description}
          onChange={(e) => setForm({ ...form, description: e.target.value })}
          required
        />
        <select
          className="form-control mb-2"
          value={form.priority}
          onChange={(e) => setForm({ ...form, priority: e.target.value })}
        >
          <option>Low</option>
          <option>Medium</option>
          <option>High</option>
        </select>
        <button className="btn btn-success">Submit</button>
      </form>

      <h3 className="mt-4">Your Complaints</h3>
      <ul className="list-group">
        {complaints.map((c) => (
          <li key={c._id} className="list-group-item">
            {c.category} - {c.description} - <b>{c.status}</b>
          </li>
        ))}
      </ul>
    </div>
  );
}
